/* ===== parse REAL ===== */
let MAXR=14;
let LIVE={round:0,scores:{},fetched:0,status:'idle',kickoffs:{},firstKickoff:null};/* live scores for current round */
const RFIX={},RPRICE={},OFFS={},RST={};
(function(){
  const fixPart=REAL.slice(REAL.indexOf('@FIX@')+5,REAL.indexOf('@PRICE@'));
  const prPart=REAL.slice(REAL.indexOf('@PRICE@')+7,REAL.indexOf('@OFF@'));
  const offPart=REAL.slice(REAL.indexOf('@OFF@')+5,REAL.indexOf('@ST@'));
  const stPart=REAL.slice(REAL.indexOf('@ST@')+4);
  const fp=fixPart.split('@');
  MAXR=+fp[0];
  fp[1].split('~').forEach(row=>{
    row=row.trim();if(!row)return;
    const i1=row.indexOf(':'),i2=row.indexOf(':',i1+1);
    const r=+row.slice(0,i1);
    const byes=row.slice(i1+1,i2).split(',').filter(x=>x!=='').map(Number);
    const games=row.slice(i2+1).split('|').filter(x=>x).map(m=>{const f=m.split(',');return[+f[0],+f[1],f[2]===''?null:+f[2],f[3]===''?null:+f[3]]});
    RFIX[r]={byes,games};
  });
  prPart.split('~').forEach(row=>{row=row.trim();if(!row)return;const[i,vals]=row.split(':');RPRICE[+i]=vals.split(',').map(v=>v===''?null:+v)});
  offPart.split('~').forEach(row=>{row=row.trim();if(!row)return;const[i,vals]=row.split(':');OFFS[+i]=vals.split(',').map(v=>v===''?null:+v)});
  stPart.split('~').forEach(row=>{row=row.trim();if(!row)return;
    const ci=row.indexOf(':');const[i,r]=row.slice(0,ci).split(',');
    const arr=row.slice(ci+1).split(',').map(v=>v===''?0:+v);
    if(!RST[+i])RST[+i]={};RST[+i][+r]=arr;
  });
})();

/* merge any saved data updates */
function applyDataPatch(){
  if(!S||!S.dataPatch)return;
  const P=S.dataPatch;
  if(P.maxR&&(isNaN(MAXR)||P.maxR>MAXR))MAXR=P.maxR;
  if(P.off)for(const pid in P.off)for(const r in P.off[pid]){if(!OFFS[pid])OFFS[pid]=[];OFFS[pid][r-1]=P.off[pid][r]}
  if(P.price)for(const pid in P.price)for(const r in P.price[pid]){if(!RPRICE[pid])RPRICE[pid]=[];RPRICE[pid][r-1]=P.price[pid][r]}
  if(P.fix)for(const r in P.fix)RFIX[r]=P.fix[r];
  if(P.st)for(const pid in P.st)for(const r in P.st[pid]){if(!RST[pid])RST[pid]={};RST[pid][r]=P.st[pid][r]}
}

/* ===== data update (fetch or file import) ===== */
function buildPatchFromFeeds(players,rounds){
  const idMap={};FEEDIDS.forEach((id,i)=>idMap[id]=i);
  const sqMap={};SQUAD_FEED_IDS.forEach((id,i)=>sqMap[id]=i);
  const doneRounds=rounds.filter(r=>r.status==='complete').map(r=>r.id);
  const newMax=doneRounds.length?Math.max(...doneRounds):MAXR;
  const oldMaxBefore=MAXR;/* snapshot before patch mutates MAXR */
  const P=S.dataPatch||{};P.maxR=Math.max(newMax,P.maxR||0);
  P.off=P.off||{};P.price=P.price||{};P.fix=P.fix||{};P.st=P.st||{};
  players.forEach(p=>{
    const i=idMap[p.id];if(i==null)return;
    for(let r=1;r<=newMax;r++){
      if(p.stats&&p.stats.scores&&p.stats.scores[r]!=null){(P.off[i]=P.off[i]||{})[r]=p.stats.scores[r]}
      if(p.stats&&p.stats.prices&&p.stats.prices[r]!=null){(P.price[i]=P.price[i]||{})[r]=Math.round(p.stats.prices[r]/1000)}
    }
  });
  rounds.forEach(rd=>{
    P.fix[rd.id]={byes:(rd.bye_squads||[]).map(x=>sqMap[x]).filter(x=>x!=null),
      games:(rd.matches||[]).map(m=>{
        const started=['active','live','in_progress','in-progress','playing','complete','completed','final'].includes(String(m.status||'').toLowerCase());
        return[sqMap[m.home_squad_id],sqMap[m.away_squad_id],started&&m.home_score!=null?m.home_score:null,started&&m.away_score!=null?m.away_score:null];
      })};
  });
  detectSooRounds(rounds);
  S.dataPatch=P;applyDataPatch();const _adv=autoAdvanceRounds(oldMaxBefore);save();return _adv;
}
async function updateData(){
  const btn=$('#btn-update');if(btn){btn.disabled=true;btn.textContent='Updating…'}
  try{
    const _loc=location.hostname==='localhost'||location.hostname==='127.0.0.1';
    const players=await fetch(_loc?'https://fantasy.nrl.com/data/nrl/players.json':'/api/players').then(r=>r.json());
    const rounds=await fetch(_loc?'https://fantasy.nrl.com/data/nrl/rounds.json':'/api/rounds').then(r=>r.json());
    const oldMax=MAXR;
    buildPatchFromFeeds(players,rounds);
    /* try to fetch detailed stat lines for new rounds (for custom scoring + breakdowns) */
    if(MAXR>oldMax){
      const idMap={};FEEDIDS.forEach((id,i)=>idMap[id]=i);
      const ORDER=STAT_KEYS.concat(['TOG']);
      const todo=players.filter(p=>idMap[p.id]!=null&&p.stats&&p.stats.scores&&Object.keys(p.stats.scores).some(r=>+r>oldMax));
      let done=0;
      for(const p of todo){
        try{
          const j=await fetch('https://fantasy.nrl.com/data/nrl/stats/players/'+p.id+'.json').then(r=>r.json());
          const i=idMap[p.id];
          for(const k in j){const r=+k;if(!(r>oldMax&&r<=MAXR))continue;
            (S.dataPatch.st[i]=S.dataPatch.st[i]||{})[r]=ORDER.map(o=>j[k][o]||0);
          }
        }catch(e){}
        done++;if(btn&&done%25===0)btn.textContent='Updating… '+done+'/'+todo.length;
      }
      applyDataPatch();save();
    }
    const newRounds=Object.keys(S.season.rounds).length;const msg=MAXR>14?('Data updated — real results through Round '+MAXR+(newRounds>0?'. Round '+S.round+' is your next upcoming round.':'.')):'Data is current — real results loaded through Round '+MAXR+'.';alert(msg);
  }catch(e){
    openModal(`<h3>Couldn't fetch automatically</h3>
    <p class="muted" style="margin:10px 0">Your browser blocked the request (CORS). Do it manually — takes 30 seconds:</p>
    <ol style="margin:0 0 12px 18px;line-height:1.7;font-size:13px">
      <li>Scores update automatically — no manual steps needed in the live app</li>
      <li>To force a refresh, use the button above</li>
      <li>Pick both files below</li>
    </ol>
    <input type="file" id="upd-files" multiple accept=".json">
    <button class="btn" style="margin-left:8px" onclick="importDataFiles()">Import</button>
    <p class="tooltip">Manual import loads official scores, prices and fixtures. (Detailed stat lines for new rounds need the auto-update; scores still work fine.)</p>`);
  }
  if(btn){btn.disabled=false;btn.textContent='⟳ Update data from NRL Fantasy'}
  renderAll();
}
async function importDataFiles(){
  const files=[...($('#upd-files').files||[])];
  if(files.length<2){alert('Select both players.json and rounds.json');return}
  let players=null,rounds=null;
  for(const f of files){
    const j=JSON.parse(await f.text());
    if(Array.isArray(j)&&j.length&&j[0].matches!==undefined)rounds=j;else players=j;
  }
  if(!players||!rounds){alert('Could not recognise the files — need players.json and rounds.json');return}
  buildPatchFromFeeds(players,rounds);
  closeModal();alert('Imported — real results loaded through Round '+MAXR+'.');autoRefresh();
}
